var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이것으로 행적 보고를 마치겠습니다.","JPN":"これにて足取りの報告を終わります。","ENG":"This concludes my report, sir.","TWN":"以上報告完畢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"정말 충격적이군.","JPN":"本当に衝撃的だな。","ENG":"Shocking.","TWN":"真是令人震驚。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그렇게 우호적이던 제프티 바이오테크가 비인도적인 실험을 자행하던 집단인 데다가…….","JPN":"あんなに友好的だったジェフティ・バイオテックが、非人道的な実験を行っていた集団である上に……","ENG":"Who would've thought Jehuty Biotech would conduct such inhumane experiments...","TWN":"曾經那麼友好的傑夫堤生物科技，竟然是進行非人道實驗的集團，而且……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>형제들</color>이란 조직은 국가에 극히 위험한 자들이죠.","JPN":"<color=#ffd34c>兄弟</color>という組織は国家に極めて脅威になる者たちです。","ENG":"The organization called <color=#ffd34c>The Brothers Abandoned</color> pose a great danger to this country.","TWN":"<color=#ffd34c>兄弟們</color>這個組織對國家而言極其危險。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그러니 말일세. 그것들이 북방합의체와 결탁했다고 하면, 매국노 같은 합병파 놈들도 한동안은 수그러들겠지만.","JPN":"そのとおりだ。それが北方合意体と結託したとあれば、売国奴のような合併派のやつらもしばらくは大人しくなるだろうが。","ENG":"You're absolutely right. Although, if they were to collude with the Northern Union, those Northern Unionist scum would also lie low for a while.","TWN":"沒錯，若他們和北方和議會勾搭上，那統一派傢伙應該也會消沉一段陣子。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"……자네는 정말 그들이 침식체를 무기로 쓰려 한다고 믿나?","JPN":"……君は本当に彼らが侵食体を武器として使おうとしていると信じているのか？","ENG":"Do you really believe they are trying to weaponize C.O.s?","TWN":"……你真的相信他們要用侵蝕體做武器嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"의심의 여지는 희박합니다. 한나 엔더슨을 사칭한 자는 결국 그림자처럼 되어 저희를 공격했으니까요.","JPN":"ほとんど疑う余地はないかと。ハンナ・アンダーソンを騙った者は、結局シャドウとなり我々を攻撃したのですから。","ENG":"Hanna Anderson's impersonator eventually became a Shadow and attacked us, leaving little room for doubt.","TWN":"可信度蠻高的，因爲冒充漢娜·安德森的人後來就成為暗影，還攻擊我們。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그래. 자네가 제출한 자료는 확실히 받았네.","JPN":"わかった。君が提出した資料は確かに受け取った。","ENG":"Very well. I have received the documents you've submitted.","TWN":"嗯，我有收到你提交的資料。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 자네도 알다시피 한나 엔더슨은 평범한 인간이었어.","JPN":"だが、君も知ってのとおり、ハンナ・アンダーソンは普通の人間だったんだ。","ENG":"However, as you know, Hanna Anderson was a normal person.","TWN":"但是你也知道，漢娜·安德森只是個普通人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"카운터도 아닌 사람이 그림자로 변하는 일은 전례가 없지 않나?","JPN":"カウンターでもない人間がシャドウとなることは前例がないだろう？","ENG":"Has there even been a case where a non-Counter turned into a Shadow?","TWN":"非制裁者的人變成暗影，這件事可說是史無前例吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그림자의 핵에 대해서도 파악하고 있던 자들입니다. 저희가 모르는 사실은 얼마든지 더 있을 수 있죠.","JPN":"シャドウの核についても把握していた者たちです。我々の知らない事実はいくらでもあると思います。","ENG":"They appear to be familiar with Shadows and their cores. Therefore, it is reasonable to assume that they know something we do not, sir.","TWN":"他們掌握暗影的核心，可能還有許多我們不知道的事情。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"임무에서 복귀하자마자 조사까지 맡아 줘서 고생 많았네. 래시포드 장교.","JPN":"任務から復帰するなり調査まで引き受けてくれてご苦労だったな。ラッシュフォード将校。","ENG":"Officer Rashford, I'm sorry to put you in charge of the investigation so soon after your return from your mission.","TWN":"才剛結束任務就著手調查，真是辛苦你了，雷斯福特軍官。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"제 성격 탓일 뿐입니다. 남에게 맡기면 기분이 편치 못해서요.","JPN":"私の性格上、人に任せると気が休まりませんので。","ENG":"Please, don't be. I wouldn't have felt comfortable leaving it to someone else.","TWN":"可能是因為我個性的緣故，交給別人處理不太放心。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그리고 일전에 얘기했던 자네에 대한 위원회의 왕실 최고 기술자 자격 검토안 말일세.","JPN":"あと、この前話した委員会の王室最高技術者の資格検討案なんだが……","ENG":"And about that Chief Technician position we talked about last time...","TWN":"還有，之前提過的，委員會對於你的皇室頂尖技師資格審查案。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"나도 찬성하기로 했네.","JPN":"私も賛成することにした。","ENG":"I have agreed to nominate you.","TWN":"我也決定贊成。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네? 애초의 목적이던 성유물의 회수에 실패했습니다만……?","JPN":"え？　当初の目的だった聖遺物の回収には失敗しておりますが……？","ENG":"I beg your pardon? But I failed to retrieve the Holy Relic...","TWN":"嗯？可是回收聖遺物任務失敗……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"자네는 우리 나라의 잠재적인 위협을 밝혀내고 그림자를 요격했어.","JPN":"君は我が国の潜在的な脅威を暴き、シャドウを撃退した。","ENG":"Nevertheless, you have uncovered a potential threat to this country and defeated a Shadow.","TWN":"你發現我們國家的潛在危機，還成功阻止暗影。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"이런 시대에 충분히 가치 있는 인재 아니겠나.","JPN":"こんな時代に十分価値のある人材ではないか。","ENG":"Don't you think that's enough to prove your worth?","TWN":"你在這個時代，完全是個有價值的人才。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"감사한 말씀이지만, 저 혼자 한 일은 결코 아닙니다.","JPN":"お言葉はありがたいのですが、決して私一人で成し遂げたことではありません。","ENG":"I appreciate your words, but I couldn't have done it by myself.","TWN":"謝謝，但這並非我一個人的功勞。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그렇지. 그래서 자네가 제안했던 남부 국경수비대에 대한 포상은 그대로 실시할 계획일세.","JPN":"ああ。だから君の提案どおり、南部国境守備隊には褒賞を与えるつもりだ。","ENG":"True. That is why I'm planning to reward the Southern Border Guards for their contribution as you suggested.","TWN":"沒錯，所以你提議的對南方國境護衛隊的獎勵計畫將如期實施。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"원래대로라면 자네들의 업적을 만천하에 공표해야 마땅한 일이지만…","JPN":"本来なら君たちの業績を世界に公表すべきなんだが……","ENG":"While your achievements ought to be announced to the whole world...","TWN":"按理說，應該將你們的功績公諸於世才對…"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"제프티 바이오테크가 관여했던 사업들을 수습하기도 바쁜 탓에 당장은 힘들 걸세.","JPN":"ジェフティ・バイオテックが関わっていた事業を収拾するのに忙しくて今すぐには無理だろう。","ENG":"We are currently so preoccupied with resolving everything involving the Jehuty Biotech scandal that it seems difficult at the moment.","TWN":"由於忙著處理傑夫堤生物科技參與的案子，所以暫時會有困難。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"어려운 시기에도 신경써 주셔서 감사합니다.","JPN":"厳しい時期にもかかわらず、お気遣いいただきありがとうございます。","ENG":"I appreciate your concern for me during these trying times, sir.","TWN":"謝謝長官在百忙之中還記得這件事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"하지만, 왕실 최고 기술자의 자리는 받지 않겠습니다.","JPN":"ですが、王室最高技術者の役職は辞退させていただきます。","ENG":"However, I won't be accepting the position.","TWN":"不過，皇室頂尖技師的位置我不能接受。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"음? 그게 무슨 소리인가?","JPN":"うむ？　それはどういうことだ？","ENG":"Hmm? What do you mean?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"부친의 유지를 이어받아 최고 기술자가 되는 것이 사관학교에 들어온 이유 아니었나?","JPN":"お父上の遺志を受け継いで最高技術者になることが士官学校に入学した理由だったのだろう？","ENG":"Didn't you enter the academy to follow your father's footsteps and become the Chief Technician?","TWN":"繼承父親的遺志成爲頂尖技師，這不是你進入軍校的原因嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그 자리는 이곳에 남아 있을 다른 훌륭한 기술자에게 넘겨 주십시오.","JPN":"その役職はこちらに残っている他の素晴らしい技術者にお譲りください。","ENG":"Please give that spot to someone who will be staying at the capital, sir.","TWN":"請將那個位置留給其他優秀的技師吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"대신, 다른 부탁을 드리고 싶습니다.","JPN":"その代わり、別のお願いがございます。","ENG":"Instead, there is a favor I wish to ask of you.","TWN":"不過，我有一事相求。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"하아… 힘들어.","JPN":"はあ……疲れた。","ENG":"*Sigh* I'm beat...","TWN":"呼… 好累。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"꾀부리지 말고 일해. 앞으로도 고쳐야 할 집이 아직 많이 남았다.","JPN":"サボってねえで働けよ。これから直さないといけない家が山ほど残ってるぞ。","ENG":"Stop slacking off and get back to work. We still have many houses left to fix.","TWN":"少在那邊裝模作樣，繼續趕工吧，還有很多房子要修呢。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"좀 봐 줘요. 저는 군인이지 목수가 아니라고요.","JPN":"ちょっと勘弁してくださいよ。僕は軍人で、大工じゃないんですって。","ENG":"Oh, c'mon. I'm a soldier, not a carpenter.","TWN":"你放過我吧，我是軍人，不是木匠。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"임마, 네 입으로 감자 캐는 일보다 더 보람된 노동을 하고 싶다면서?","JPN":"こら、お前の口がジャガイモを掘るよりもっとやり甲斐のある労働がしたいって言ったんじゃねえか。","ENG":"Hey, you're the one who said you wanted to do something more rewarding than digging up potatoes?","TWN":"小子，你不是說想做比挖馬鈴薯更有意義的工作嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"목공일을 배운다고 했지, 새 집을 짓겠다고 한 적은 없어요.","JPN":"大工の仕事を教わるって言っただけで、新しい家を建てるなんて言ったことはないですよ。","ENG":"I said I wanted to learn carpentry, not build houses all day long.","TWN":"我說要學木匠的工作，可沒說過要蓋新房子。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L46_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아니, 이 녀석이 왜 나한테 불평이야?","JPN":"おい、なんで俺に文句言ってんだ？","ENG":"Hey! What are you complaining to me about?","TWN":"真是的，你這傢伙為什麼對我發牢騷？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"내가 이 집들 다 무너트렸냐? 침식체 놈들이 그랬지?","JPN":"俺がこの家を壊したんじゃねえだろ？　侵食体がやったんだよ。","ENG":"Did I destroy these houses? It was the C.O.s, no?!","TWN":"是我破壞這些房子的嗎？是侵蝕者幹的吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"두 사람, 주민들 앞에서 싸우지 말라고 경고했을 텐데.","JPN":"二人とも、住民の前でケンカするなと警告したはずだ。","ENG":"You two, I thought I told you not to fight in front of the villagers.","TWN":"你們二個，我說過不要在居民面前吵架。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"오, 오해이십니다. 마침 침식체에 대한 분노를 상기하고 있었을 뿐이죠.","JPN":"ご、誤解です。ちょうど侵食体への怒りを思い出してただけなんです。","ENG":"W-we weren't, ma'am. We were just reminding ourselves of our hatred for the C.O.s.","TWN":"哦，誤會誤會。我只是在回憶對侵蝕體的憤怒。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"빌어먹을 침식체 놈들! …아, 대장님 오셨습니까?","JPN":"クソ侵食体野郎！　……あ、隊長。","ENG":"Those damned C.O.s...! Oh, Captain, didn't see you there.","TWN":"該死的侵蝕體！ …喔，隊長來啦？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"곧 식사 시간이야. 이거 먹고 따라 와.","JPN":"もうすぐ食事の時間だ。これを食べてついて来い。","ENG":"It's almost time to eat. Eat this and follow me.","TWN":"就快到吃飯時間了，吃完這個跟我來。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"으음, 감자가 오늘따라 유독 하얀 것 같은데……","JPN":"うーん、今日はジャガイモが余計に白く見えるんだけど……","ENG":"Mm... Why does the potato look so white today...?","TWN":"呃，今天的馬鈴薯好像特別白………"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"우왓! 이거 계란이잖아요?!","JPN":"うわっ！　これタマゴじゃないですか！？","ENG":"Whoa! Isn't this an egg?!","TWN":"哇！這不是雞蛋嗎？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐? 그게 정말이냐?!","JPN":"なっ？　本当か！？","ENG":"What?! Really?!","TWN":"什麼？是真的嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"이틀 전 도시 오일장에서 암탉을 내놨더라고요. 이번에 엘라님이 큰 맘 먹고 몇 마리 들여왔습니다.","JPN":"二日前、都市の市場にめんどりがいたんですよ。今回エラ様が気前よく何匹か買ってくださいました。","ENG":"The city market had some hens for sale two days ago. Miss Ella bought a few for all of us.","TWN":"二天前我在菜市場有看到母雞，然後艾拉就狠下心來買了幾隻。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"막상 방목을 해서 키우려니 들짐승들이 어슬렁거려서 문제야.","JPN":"放し飼いで育てたいけど、野生動物がうろついているのが問題だな。","ENG":"However, I'm afraid that wild animals will snatch them away if we let them graze while we raise them.","TWN":"要放養的話，重點是要如何防範野獸。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"누가 닭장 좀 만들어 줄래?","JPN":"誰か鶏小屋を作ってくれないか？","ENG":"Could one of you build a chicken coop for me?","TWN":"誰幫我做雞舍？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"맡겨 주시죠! 저희가 금방 만들어드리겠습니다!","JPN":"任せてください！　俺らがすぐ作ります！","ENG":"Leave it to me! I'll make one right away!","TWN":"交給我吧！我們馬上替你做！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그럼 부탁드립니다, 와트 씨.","JPN":"それじゃあお願いします、ワットさん。","ENG":"Then I leave it to you, Mr. Watt.","TWN":"那就麻煩你囉，華特先生。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"계란은 방금 네가 먹었잖아.","JPN":"お前、さっき卵食ったじゃねえか。","ENG":"Hey! You just ate yours! This one's mine!","TWN":"你剛不是也有吃雞蛋嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"정말 맛있네요. 이럴 때 큐리안 대장님이 계셨다면 먼저 드렸을 텐데.","JPN":"本当においしいですね。こういう時キュリアン隊長がいたら先にさしあげたのに。","ENG":"It's really good! I wish Captain Curian was here. I would've given him one too.","TWN":"真的很好吃欸，這時候如果庫里安隊長在的話，我會先給他的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"야, 이 눈치 없는 자식아! 대장 얘기는 엘라님 앞에서 하지 않기로 했잖아.","JPN":"おい、気の利かないやつめ！　エラ様の前で隊長の話はしない約束だろうが。","ENG":"Hey, you dimwit! I said to not talk about Captain in front of her!","TWN":"喂，你這個沒腦袋的傢伙！不是說好不要在艾拉小姐面前提到隊長的嘛。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"아차…","JPN":"おっと……","ENG":"Oops...","TWN":"哎呀…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"괜찮아. 그건 전부 큐리안이 택한 결정이었어. 군인이란 스스로 책임을 지는 법이니까.","JPN":"問題ない。全部キュリアンが選んだことだ。軍人とは自ら責任を取るものだから。","ENG":"It's all right. It was Curian's decision after all. Something about soldiers taking responsibility for themselves and whatnot.","TWN":"沒關係，那都是庫里安選擇的決定，因爲軍人要自己負責。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다들 내 얘기를 하던 중이었나?","JPN":"みんな、私の話をしてたのか？","ENG":"Were you guys talking about me?","TWN":"大家在說我喔？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"…대장님. 돌아오신 타이밍이 조금 나쁜 것 같은데요.","JPN":"……隊長。戻ってくるタイミングがちょっとよくなかったと思いますよ。","ENG":"...Captain. Kind of a bad timing for you to return, sir.","TWN":"…隊長，你回來的時機好像有點不好。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"설명해 봐, 큐리안.","JPN":"説明してみて、キュリアン。","ENG":"Explain yourself, Curian.","TWN":"請解釋一下，庫里安。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이번엔 이틀 동안 어딜 또 멋대로 사라졌던 거지?","JPN":"今度は2日も勝手にどこへ消えてたの？","ENG":"Where have you been for the past 2 days?","TWN":"這二天又跑到哪裡去都沒看到人？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"걱정을 끼쳤다면 미안하군, 엘라 부관. 고기가 필요해서 사슴 사냥을…","JPN":"心配をかけたならすまない、エラ副官。肉が必要だったから鹿を狩りに……","ENG":"Sorry if I made you worry, Adjutant Ella. I went out hunting deer for some meat─","TWN":"抱歉讓你擔心，艾拉副隊長，因為需要肉，所以我去獵鹿…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…커헉!","JPN":"……ぐはっ！","ENG":"Kuh...!","TWN":"…咳咳！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"고작 그런 이유로 부대의 대장이 이틀씩이나 멋대로 자리를 비워?","JPN":"そんな理由で部隊の隊長が2日も勝手に席を外してたの？","ENG":"You're saying that the captain left his men for 2 days all for some stupid deer meat?","TWN":"就因爲這個原因，部隊的隊長竟然連續二天擅離職守？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아직도 자길 참모라고 착각하고 있는 거야? 대장이라는 위치에 대한 자각이 없어?","JPN":"まだ自分が参謀だと勘違いしてるんじゃない？　隊長という立場に自覚はないの？","ENG":"What? Do you still think you're just an advisor here? Have you not realized that you're the captain of the Southern Border Guards now?","TWN":"你還誤以爲自己是指揮官嗎？你對隊長這個位置沒有認知嗎?"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"숨을… 쉴 수가…","JPN":"息が……できな……","ENG":"I... can't breathe...","TWN":"不能… 呼吸…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"고기 타령은 하지도 않던 인간이 갑자기 무슨 사슴 사냥을 나간 거지?","JPN":"普段は肉なんて言いもしない人間が、いきなりなんで鹿を狩りに行ったの？","ENG":"What got into you all of a sudden that made you go out hunting deer?","TWN":"一個嘴巴從沒提到肉的人，突然跑出去獵鹿？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그게… 부하들이 먹고 싶다고…","JPN":"それが……部下が食べたいと……","ENG":"Well... my men said they wanted to eat it, so...","TWN":"那個… 部下說想吃…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"부하? 대체 누굴 말하는 거야?","JPN":"部下？　いったい誰のことだ？","ENG":"Your men, eh? And who might that be?","TWN":"部下？是指誰？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그건… 말하지 않겠다.","JPN":"それは……言わないでおこう。","ENG":"That's... my lips are sealed.","TWN":"那個… 我不能說。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…말하지 않아도 알겠어.","JPN":"……言わなくてもわかる気がするけど。","ENG":"No need to tell me. I think I already know who they are.","TWN":"…不說也知道。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래서? 결국 사슴은 잡은 거야?","JPN":"それで？　結局鹿狩りには成功したの？","ENG":"So? Were you able to hunt any?","TWN":"所以呢？是抓到鹿嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_KID","text":{"KOREA":"우와, 맛있는 냄새다!","JPN":"うわ、いい匂い！","ENG":"Whoa! It smells so good!","TWN":"哇喔，好香喔！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"엘라님, 갑자기 이게 무슨 고기래요? 오늘은 도시에 다녀온 사람도 없는 걸로 아는데?","JPN":"エラ様、突然お肉なんてどうしたんですか？　今日は都市に行ってきた人もいないでしょう？","ENG":"Miss Ella, where did the meat come from? I didn't know someone went to the city today.","TWN":"艾拉，這是什麼肉？ 我記得今天沒人去城裡吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"큐리안 대장이 멋대로 잡아왔어요. 오늘 저녁은 고기 스튜니까, 양껏 드세요.","JPN":"キュリアン隊長が勝手に捕ってきました。今日の夕飯はお肉のシチューですから、たくさん食べてください。","ENG":"Captain Curian decided to hunt for it. Today's menu is deer stew, so please enjoy.","TWN":"是庫里安隊長自己抓的，今晚的菜色是燉肉，請盡情享用。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_KID","text":{"KOREA":"피터 형이랑 와트 아저씨가 안 보이는데, 제가 데려올까요?","JPN":"ピーター兄ちゃんとワットおじさんがいないんだけど、僕が連れてこようか？","ENG":"I don't see Peter or Mr. Watt... Should I go find them?","TWN":"彼得哥哥和華特叔叔沒看到人，要我把他們帶過來嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_NULL_KID","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"찾지 마. 그 두 사람은 오늘 생감자만 실컷 먹게 될 테니까.","JPN":"探さなくていい。あの二人は今日生ジャガイモをたらふく食べることになるだろうから。","ENG":"No. Those two will be eating nothing but raw potatoes today.","TWN":"別管他們，他們二個今天就只能吃生馬鈴薯。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"…엘라님!","JPN":"……エラ様！","ENG":"Miss Ella!","TWN":"…艾拉！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"생각보다 빨리 왔네. 양심의 끈이 벌써 떨어진 거야?","JPN":"思ったより早かったな。良心はどこかに置いてきたのか？","ENG":"You're back early. Did you already lose your sense of conscience?","TWN":"還真是說曹操曹操到？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그게 아니라… 손님이 찾아오셨습니다.","JPN":"そうじゃなくて……お客さんがお見えです。","ENG":"It's not that... We have a guest.","TWN":"不是啦…你有客人。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"손님?","JPN":"お客？","ENG":"A guest?","TWN":"客人？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"래시포드 장교님…?","JPN":"ラッシュフォード将校……？","ENG":"Officer Rashford...?","TWN":"雷斯福特軍官…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"오랜만이다, 엘라 대장.","JPN":"久しぶりだな、エラ隊長。","ENG":"Long time no see, Captain Ella.","TWN":"好久不見，艾拉隊長。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"내가 떠날 때보다 마을이 좀 더 활기를 찾은 것 같군. 별탈 없이 잘 지냈나?","JPN":"私がここを離れた時より村がもっとにぎやかになったようだ。元気だったか？","ENG":"The village appears to be more lively than when I left. How have you been?","TWN":"村莊好像比我離開時恢復不少，過得還好嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저는 더 이상 대장이 아니라 참모입니다. 그날 이후로 큐리안에게 권한을 모두 인계했으니까요.","JPN":"私はもう隊長ではなく参謀です。あの日以来、キュリアンにすべての権限を譲りましたから。","ENG":"I'm not the captain anymore. I'm just an advisor. I left Curian in charge of everything.","TWN":"我已經不是隊長，而參謀。從那天以後，我已經把權限全部移交給庫里安。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그랬나? 그럼 지금은 편하게 엘라라고 부르도록 하지.","JPN":"そうだったのか？　なら、今はエラと呼ぶとしよう。","ENG":"Oh really? Then I'll call you Ella from now on.","TWN":"是嗎？那現在就叫你艾拉吧"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"여긴 어쩐 일이시죠? 재건단의 명령으로 성유물을 회수하러 찾아오신 거라면…","JPN":"今日はどうされましたか？　再建団の命令で聖遺物を回収しに来たのなら……","ENG":"What brings you here? If you're here under orders to bring back the Holy Relic...","TWN":"你怎麼會來？若你是奉重建委員會之命前來追回聖遺物…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런 걱정은 말도록. 이번엔 상부의 임무 때문에 여기까지 내려온 게 아니니까.","JPN":"そういう心配はしなくていい。今回は上層部からの任務でここまで来たわけではないからな。","ENG":"Don't worry about that. I'm not here on a mission like last time.","TWN":"不用擔心，我這次來不是因爲上級的任務。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"임무도 아닌데, 일부러 수도에서 이런 먼 곳까지 찾아오신 건가요?","JPN":"任務でもないのに、わざわざ首都からこんな遠いところまでいらしたのですか？","ENG":"If you're not here on a mission, then why would you travel so far away from the capital?","TWN":"又沒有任務，你特地從首都遠道而來嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"좌천됐다.","JPN":"左遷されたんだ。","ENG":"I've been demoted.","TWN":"我被降職了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"성유물 회수를 실패한 데 책임을 지고, 앞으로는 남부 국경수비대에 기술교관을 맡게 됐어.","JPN":"聖遺物の回収に失敗した責任を取って、これからは南部国境守備隊の技術教官を担当することになったんだ。","ENG":"I've been assigned as the Technical Instructor for the Southern Border Guards after accepting full responsibility for failing to retrieve the Holy Relic.","TWN":"我要負起回收聖遺物失敗的負責，今後將在南方國境護衛隊擔任科技教官。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"뜻밖이군요. 재건단이 정말로 장교님 같은 유능한 분을 이런 변방으로 내친 겁니까?","JPN":"意外ですね。再建団が本当に将校のような有能な方をこんな辺境に追い出したのですか？","ENG":"How unusual... I can't believe the Alliance would throw away a competent officer like you to a place like this...","TWN":"真意外，重建委員會真的將你這樣的人才趕到這種偏僻的地方嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥. 칭찬의 뜻으로 받아들이지.","JPN":"フン。褒め言葉だと思っておく。","ENG":"Hmph. I'll take that as a compliment.","TWN":"哼，我就當你是在稱讚我。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"앞으로 잘 부탁하마.","JPN":"これからよろしく頼む。","ENG":"Anyway, I look forward to working with you.","TWN":"往後請多指教。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그리고…","JPN":"それから……","ENG":"Also...","TWN":"還有…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"남부 국경수비대 부관 엘라. 그대는 그림자 토벌의 공로를 인정받아, 현 시간부로 국가 재건단 총사대 중 제1번대 총사로 임명한다.","JPN":"南部国境守備隊の副官エラ。あなたのシャドウ討伐の功労を認め、現時点をもって国家再建団銃士隊の第1番隊銃士に任命する。","ENG":"Miss Ella, Adjutant of the Southern Border Guards. Your contributions towards defeating a Shadow have been acknowledged, and you are hereby appointed 1st Commander of the Alliance's Musketeer Division.","TWN":"南方國境護衛隊副隊長艾拉， 你討伐暗影有功，即刻起任命你為國家重建委員會射擊隊中的第1射擊隊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"총사대… 말씀이십니까?","JPN":"銃士隊……ですか？","ENG":"Musketeer Division...?","TWN":"你是說… 射擊隊嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"음? 혹시 어떤 지위인지 모르나?","JPN":"うむ？　もしかしてどんな役職なのか知らないのか？","ENG":"Mm? Do you not know what that position means?","TWN":"嗯？不知道是什麼位置嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아뇨. 성자… 그러니까, 왕립군에 소속된 카운터들 중에서도 왕의 신임을 받는 뛰어난 군인에게 주어지는 명예라고 알고 있습니다.","JPN":"いいえ。聖者……ですから、王立軍所属のカウンターの中でも王から信頼を得た優れた軍人に与えられる名誉と存じております。","ENG":"I do... I heard it was an honor bestowed upon outstanding Helgo– I mean, Royal Army Counters, trusted by the king.","TWN":"不是，聖者… 據我所知，在隸屬於皇家軍隊的制裁者中，這是授予得到國王信任之優秀軍人的榮譽。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식의 날 이후로 총사대는 사실상 해체된 걸로 알고 있습니다만.","JPN":"ですが、侵食の日以来、銃士隊は事実上解体されたと思いましたが。","ENG":"However, to my understanding, the Musketeer Division was disbanded after the Day of Corruption...","TWN":"據我所知，侵蝕之日後，射擊隊實際上已經是解散的狀態。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그 말대로다. 왕이 사라진 이상, 예전 의미를 그대로 간직한 총사대는 더 이상 없겠지.","JPN":"そのとおりだ。王が消えた以上、昔の意味そのままの銃士隊はもうないだろう。","ENG":"Correct. With no king left to rule this country, the original meaning of the Musketeer Division has been lost.","TWN":"正如你所說，既然已消失，就沒必再保留以前的射擊隊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"총사대 재결성은, 노르드나빅의 전성기를 떠올리며 시작한 프로젝트의 일환이다.","JPN":"銃士隊の再結成は、ノルドナビックの最盛期を思い出しながら始めたプロジェクトの一環だ。","ENG":"However, the reorganization of the Musketeer Division is part of the Alliance's project to honor the golden age of Nordnavik.","TWN":"重新設立射擊隊，是想起諾爾德萊比全盛時期而開始的一環。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그리고 귀관은 우리의 마지막 희망인 성유물을 지키기 위해 목숨을 걸고 싸웠어.","JPN":"そして貴官は我々の最後の希望である聖遺物を守るために命を懸けて戦った。","ENG":"And you risked your life to protect our last hope, the Holy Relic.","TWN":"還有，你拼死守護我們最後的希望 聖遺物。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"적어도 나는 귀관이 총사대장의 의지를 잇기에 자격이 충분하다고 판단했다.","JPN":"少なくとも私は貴官が銃士隊長の意志を受け継ぐに十分な資格を有していると判断したんだ。","ENG":"At the very least, I am confident that you are more than qualified to succeed as the General Musketeer.","TWN":"至少我認爲你完全有資格繼承射擊隊長的遺志。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"물론, 귀관이 원치 않는다면 억지로 강요하진 않겠어.","JPN":"もちろん貴官が望まないのであれば無理に強要はしない。","ENG":"Of course, I'm not forcing you to accept this position if you don't want it.","TWN":"當然，如果你不願意，那我也不會勉強你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"무척 영광이라고 생각합니다만…","JPN":"とても光栄ですが……","ENG":"It would be an honor. However...","TWN":"我感到非常榮幸，只是… "},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…명색이 총사대인데, 총을 쏘지 못하는 일원이 있어도 괜찮겠습니까?","JPN":"……名目上は銃士隊なのに、銃を撃てない一員がいてもよろしいのですか？","ENG":"...Would it be acceptable if the First Musketeer can't shoot a gun?","TWN":"…名義上是射擊隊，有不會開槍的成員也沒關係嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"응…? 총을 쏘지 못한다고?","JPN":"うむ……？　銃を撃てない？","ENG":"Hmm...? You don't know how to shoot a gun?","TWN":"嗯…？不會開槍？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"엘라 부관에겐 화약 알러지가 있습니다.","JPN":"エラ副官は火薬アレルギーがあります。","ENG":"Ella is allergic to gun powder.","TWN":"艾拉副隊長對火藥過敏。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래서 보통은 전투가 벌어질 때도 다른 대원들과 함께 싸우지 않고 거리를 둡니다.","JPN":"ですので、普段は戦闘が発生しても他の隊員と一緒に戦わずに距離を置いています。","ENG":"That is why whenever there is a battle she's always far away from the others.","TWN":"所以一般在戰鬥時，也不會和其他隊員一起戰鬥，會保持距離。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"일전에도 제가 대장인 그녀를 대신해 지휘를 맡았던, 가장 큰 이유였죠.","JPN":"この前の戦闘でも、私が隊長である彼女の代わりに指揮を受け持った、最大の理由でした。","ENG":"It's also the biggest reason why I commanded the troops instead of her.","TWN":"這也是我之前代替她當指揮官最大的原因。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"건강해 보이는군, 큐리안 대장.","JPN":"元気そうだな、キュリアン隊長。","ENG":"Good to see you're doing well, Captain Curian.","TWN":"你看起來很健康呢，庫里安隊長。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다시 뵙게 되어 영광입니다, 장교님.","JPN":"またお会いできて光栄です、将校。","ENG":"It's an honor to meet you again, Officer Rashford.","TWN":"能再次見到你是我的榮幸，軍官。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"못 본 새 많이 성장하신 것 같군요.","JPN":"見ない間にずいぶん成長なさいましたね。","ENG":"You seem to have grown a bit since the last time I saw you.","TWN":"一段時間沒看到你，似乎長大不少。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…이미 성인이라니까.","JPN":"……もう大人だと言っただろう。","ENG":"...I told you already I'm not a child.","TWN":"…就說我已經是大人。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};